// Row-major (D x D) Q for a given lmax (D=(lmax+1)^2); sets *dim, returns nullptr if unsupported.
inline const double *Q(int lmax, int *dim) {
  switch (lmax) {
    case 0: *dim = 1; return Q_L0;
    case 1: *dim = 4; return Q_L1;
    case 2: *dim = 9; return Q_L2;
    case 3: *dim = 16; return Q_L3;
    case 4: *dim = 25; return Q_L4;
    default: *dim = 0; return nullptr;
  }
}

// out[r,:] = x[r,:] @ Q  (x,out are rows x D row-major). ICTD -> original-MACE/e3nn basis.
inline void to_mace_basis(const double *x, double *out, int rows, int lmax) {
  int dim; const double *q = Q(lmax, &dim);
  if (!q) return;
  for (int r = 0; r < rows; ++r)
    for (int j = 0; j < dim; ++j) {
      double s = 0.0;
      for (int i = 0; i < dim; ++i) s += x[r * dim + i] * q[i * dim + j];
      out[r * dim + j] = s;
    }
}

